DROP VIEW "invoice";--> statement-breakpoint
CREATE VIEW "invoice" AS (select "aggregate_id" as "id", (array_agg("payload"#>>'{changes,project_id,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,project_id}', 'to')))[1]::uuid as "project_id", (array_agg("payload"#>>'{changes,invoice_number,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,invoice_number}', 'to')))[1] as "invoice_number", (array_agg("payload"#>>'{changes,stripe_id,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,stripe_id}', 'to')))[1] as "stripe_id", (array_agg("payload"#>>'{changes,stripe_payment_page,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,stripe_payment_page}', 'to')))[1] as "stripe_payment_page", (array_agg("recorded_at" ORDER BY "version" ASC))[1] as "created_at", ((array_agg("payload"#>>'{changes,total,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,total}', 'to')))[1])::numeric as "total" from "event" where "event"."aggregate_type" = 'invoice' group by "event"."aggregate_id");